-- ==================================================-- ENABLE FOREIGN KEYS-- ==================================================PRAGMA foreign_keys = ON;-- ==================================================-- DROP TABLES (SAFE RESET - avoids duplicate errors)-- ==================================================DROP TABLE IF EXISTS Payment;DROP TABLE IF EXISTS Booking;DROP TABLE IF EXISTS MovieShow;DROP TABLE IF EXISTS Customer;DROP TABLE IF EXISTS Movie;DROP TABLE IF EXISTS Theatre;-- ==================================================-- CREATE TABLES-- ==================================================CREATE TABLE Customer (    CustomerID INTEGER PRIMARY KEY AUTOINCREMENT,    CustomerName TEXT NOT NULL,    Phone TEXT,    Email TEXT);CREATE TABLE Movie (    MovieID INTEGER PRIMARY KEY AUTOINCREMENT,    MovieName TEXT NOT NULL,    Genre TEXT,    Duration INTEGER,    Language TEXT);CREATE TABLE Theatre (    TheatreID INTEGER PRIMARY KEY AUTOINCREMENT,    TheatreName TEXT NOT NULL,    Location TEXT);CREATE TABLE MovieShow (    ShowID INTEGER PRIMARY KEY AUTOINCREMENT,    MovieID INTEGER NOT NULL,    TheatreID INTEGER NOT NULL,    ShowDate TEXT NOT NULL,    ShowTime TEXT NOT NULL,    TicketPrice REAL NOT NULL,    FOREIGN KEY (MovieID) REFERENCES Movie(MovieID),    FOREIGN KEY (TheatreID) REFERENCES Theatre(TheatreID));CREATE TABLE Booking (    BookingID INTEGER PRIMARY KEY AUTOINCREMENT,    CustomerID INTEGER NOT NULL,    ShowID INTEGER NOT NULL,    SeatNumber TEXT NOT NULL,    BookingDate TEXT NOT NULL,    FOREIGN KEY (CustomerID) REFERENCES Customer(CustomerID),    FOREIGN KEY (ShowID) REFERENCES MovieShow(ShowID));CREATE TABLE Payment (    PaymentID INTEGER PRIMARY KEY AUTOINCREMENT,    BookingID INTEGER NOT NULL,    Amount REAL NOT NULL,    PaymentMethod TEXT,    PaymentStatus TEXT,    FOREIGN KEY (BookingID) REFERENCES Booking(BookingID));-- ==================================================-- IN